import { execute, newId, nowIso, query } from "../database";
import { journalEntityWrite } from "../syncJournal";

export type QuestStatus = "active" | "completed" | "failed";

export interface Quest {
  id: string;
  chatId: string;
  name: string;
  description: string;
  status: QuestStatus;
  createdAt: string;
  updatedAt: string;
}

interface QuestRow {
  id: string;
  chat_id: string;
  name: string;
  description: string;
  status: string;
  created_at: string;
  updated_at: string;
}

function toQuest(row: QuestRow): Quest {
  return {
    id: row.id,
    chatId: row.chat_id,
    name: row.name,
    description: row.description,
    status: row.status as QuestStatus,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** List all quests for a chat, active first, then completed, then failed. */
export async function listQuests(chatId: string): Promise<Quest[]> {
  const rows = await query<QuestRow>(
    `SELECT * FROM quests WHERE chat_id = $1
     ORDER BY CASE status
       WHEN 'active' THEN 0
       WHEN 'completed' THEN 1
       WHEN 'failed' THEN 2
     END, created_at ASC`,
    [chatId],
  );
  return rows.map(toQuest);
}

/** Get a single quest by name within a chat (for upsert logic). */
export async function getQuestByName(
  chatId: string,
  name: string,
): Promise<Quest | null> {
  const rows = await query<QuestRow>(
    "SELECT * FROM quests WHERE chat_id = $1 AND name = $2",
    [chatId, name],
  );
  return rows[0] ? toQuest(rows[0]) : null;
}

export interface CreateQuestInput {
  chatId: string;
  name: string;
  description?: string;
}

/** Create a new quest (active by default). */
export async function createQuest(input: CreateQuestInput): Promise<Quest> {
  const id = newId();
  const now = nowIso();
  await execute(
    `INSERT INTO quests (id, chat_id, name, description, status, created_at, updated_at)
     VALUES ($1, $2, $3, $4, 'active', $5, $5)`,
    [id, input.chatId, input.name, input.description ?? "", now],
  );
  const quest: Quest = {
    id,
    chatId: input.chatId,
    name: input.name,
    description: input.description ?? "",
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  journalEntityWrite("quest", quest as unknown as Record<string, unknown>);
  return quest;
}

/** Update a quest's status (active / completed / failed). */
export async function updateQuestStatus(
  id: string,
  status: QuestStatus,
): Promise<void> {
  const now = nowIso();
  await execute(
    "UPDATE quests SET status = $2, updated_at = $3 WHERE id = $1",
    [id, status, now],
  );
  journalEntityWrite("quest", { id, status, updated_at: now });
}

/** Append a progress note to the quest description. */
export async function addQuestNote(id: string, note: string): Promise<void> {
  const now = nowIso();
  await execute(
    `UPDATE quests SET
       description = CASE
         WHEN description = '' THEN $2
         ELSE description || '\n' || $2
       END,
       updated_at = $3
     WHERE id = $1`,
    [id, note, now],
  );
  journalEntityWrite("quest", { id, _note: note, updated_at: now });
}

import Database from "@tauri-apps/plugin-sql";

const DB_URL = "sqlite:mysillytavern.db";
const CACHE_TTL = 5_000; // 5 seconds

let dbPromise: Promise<Database> | null = null;

/** Lazily opens (and caches) the single SQLite connection for the app. */
export function getDb(): Promise<Database> {
  if (!dbPromise) {
    dbPromise = Database.load(DB_URL);
  }
  return dbPromise;
}

// -- Query cache --
const cache = new Map<string, { data: unknown; expires: number }>();

function cacheKey(sql: string, params: unknown[]): string {
  return `${sql}|${JSON.stringify(params)}`;
}

/** Clear the entire cache. Called after any write (execute). */
export function invalidateCache(): void {
  cache.clear();
}

export async function query<T>(sql: string, params: unknown[] = []): Promise<T[]> {
  const key = cacheKey(sql, params);
  const entry = cache.get(key);
  if (entry && entry.expires > Date.now()) {
    return entry.data as T[];
  }
  const db = await getDb();
  const result = await db.select<T[]>(sql, params);
  cache.set(key, { data: result, expires: Date.now() + CACHE_TTL });
  return result;
}

export async function execute(sql: string, params: unknown[] = []): Promise<void> {
  const db = await getDb();
  await db.execute(sql, params);
  // Any write invalidates the entire cache — simple and safe
  cache.clear();
}

export function newId(): string {
  return crypto.randomUUID();
}

export function nowIso(): string {
  return new Date().toISOString();
}

import { create } from "zustand";

import {
  createChat,
  deleteChat,
  listChats,
  renameChat,
  setChatConnection,
  setChatPersona,
  setChatPreset,
  setExtractionConnection,
  type Chat,
  type ChatDraft,
} from "../db/repositories/chatsRepo";

interface ChatListState {
  chats: Chat[];
  loaded: boolean;
  load: () => Promise<void>;
  create: (draft: ChatDraft) => Promise<Chat>;
  rename: (id: string, title: string) => Promise<void>;
  setConnection: (id: string, connectionId: string | null) => Promise<void>;
  setPersona: (id: string, personaId: string | null) => Promise<void>;
  setPreset: (id: string, presetId: string | null) => Promise<void>;
  setExtractionConnection: (id: string, connectionId: string | null) => Promise<void>;
  remove: (id: string) => Promise<void>;
}

export const useChatListStore = create<ChatListState>((set, get) => ({
  chats: [],
  loaded: false,

  load: async () => {
    const chats = await listChats();
    set({ chats, loaded: true });
  },

  create: async (draft) => {
    const created = await createChat(draft);
    set({ chats: [created, ...get().chats] });
    return created;
  },

  rename: async (id, title) => {
    await renameChat(id, title);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, title } : c)) });
  },

  setConnection: async (id, connectionId) => {
    await setChatConnection(id, connectionId);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, connectionId } : c)) });
  },

  setPersona: async (id, personaId) => {
    await setChatPersona(id, personaId);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, personaId } : c)) });
  },

  setPreset: async (id, presetId) => {
    await setChatPreset(id, presetId);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, presetId } : c)) });
  },

  setExtractionConnection: async (id, connectionId) => {
    await setExtractionConnection(id, connectionId);
    set({
      chats: get().chats.map((c) => (c.id === id ? { ...c, extractionConnectionId: connectionId } : c)),
    });
  },

  remove: async (id) => {
    await deleteChat(id);
    set({ chats: get().chats.filter((c) => c.id !== id) });
  },
}));

import { useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useAndroidBack } from "../useAndroidBack";

export type PanelType =
  | "memory"
  | "inventory"
  | "quests"
  | "director"
  | "character"
  | "group"
  | "export";

/**
 * Manages the mutually-exclusive header panel state (memory, inventory,
 * quests, director, character, group, export). Opening one panel closes any
 * other that was open.
 *
 * Also wires the Android back button to close panels before navigating away.
 */
export function useChatPanels() {
  const navigate = useNavigate();
  const [activePanel, setActivePanel] = useState<PanelType | null>(null);

  const openPanel = useCallback((panel: PanelType) => setActivePanel(panel), []);
  const closePanel = useCallback(() => setActivePanel(null), []);
  const togglePanel = useCallback(
    (panel: PanelType) => setActivePanel((p) => (p === panel ? null : panel)),
    [],
  );

  // Convenience booleans
  const memoryOpen = activePanel === "memory";
  const inventoryOpen = activePanel === "inventory";
  const questsOpen = activePanel === "quests";
  const directorOpen = activePanel === "director";
  const characterOpen = activePanel === "character";
  const groupOpen = activePanel === "group";
  const exportOpen = activePanel === "export";
  const hasOpenPanel = activePanel !== null;

  // Per-panel setters that accept boolean | toggle callback (preserves the
  // original signature used in onClick / onClose callbacks).
  const setMemoryOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "memory") : v) ? "memory" : null)),
    [],
  );
  const setInventoryOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "inventory") : v) ? "inventory" : null)),
    [],
  );
  const setQuestsOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "quests") : v) ? "quests" : null)),
    [],
  );
  const setDirectorOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "director") : v) ? "director" : null)),
    [],
  );
  const setCharacterOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "character") : v) ? "character" : null)),
    [],
  );
  const setGroupOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "group") : v) ? "group" : null)),
    [],
  );
  const setExportOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "export") : v) ? "export" : null)),
    [],
  );

  // Android back button: close panels first, then navigate back
  useAndroidBack({ hasOpenPanel }, () => {
    if (exportOpen) setActivePanel(null);
    else if (memoryOpen) setActivePanel(null);
    else if (inventoryOpen) setActivePanel(null);
    else if (questsOpen) setActivePanel(null);
    else if (characterOpen) setActivePanel(null);
    else if (directorOpen) setActivePanel(null);
    else if (groupOpen) setActivePanel(null);
    else navigate(-1);
  });

  return {
    activePanel,
    openPanel,
    closePanel,
    togglePanel,
    // Convenience booleans
    memoryOpen,
    inventoryOpen,
    questsOpen,
    directorOpen,
    characterOpen,
    groupOpen,
    exportOpen,
    hasOpenPanel,
    // Legacy per-panel setters for direct boolean/toggle control
    setMemoryOpen,
    setInventoryOpen,
    setQuestsOpen,
    setDirectorOpen,
    setCharacterOpen,
    setGroupOpen,
    setExportOpen,
  };
}

