    monthIndex: 5, // Měsíc bouří
    dayRange: [20, 28],
    description: "Šlechta pořádá velkolepý ples. Příležitost pro diplomacii, klepy i tanec.",
    icon: "💃",
  },
  {
    title: "Svátek lovců",
    monthIndex: 7, // Měsíc sklizně
    dayRange: [5, 12],
    description: "Lovci se vydávají na velkou výpravu. Kdo uloví největší zvěř, získává čest.",
    icon: "🏹",
  },
  {
    title: "Den knih",
    monthIndex: 0, // Měsíc probuzení
    dayRange: [20, 28],
    description: "Písaři a učenci vystavují vzácné svitky. Knihovny jsou otevřeny všem.",
    icon: "📚",
  },
  {
    title: "Obřad probuzení",
    monthIndex: 0, // Měsíc probuzení
    dayRange: [1, 8],
    description: "Země se probouzí po zimě. Kněží žehnají polím a sadům.",
    icon: "🌱",
  },
  {
    title: "Výročí korunovace",
    monthIndex: 6, // Měsíc sklizně
    dayRange: [12, 18],
    description: "Královský průvod prochází hlavním městem. Koruna je vystavena v katedrále.",
    icon: "👑",
  },
  {
    title: "Dětský den",
    monthIndex: 2, // Měsíc květů
    dayRange: [1, 8],
    description: "Děti dostávají drobné dárky. V ulicích se hrají hry, loutkové divadlo baví malé i velké.",
    icon: "🎈",
  },
];

/** Random integer in [min, max] inclusive. */
function randInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

/** Fisher-Yates shuffle (in-place). */
function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

/** Generates 5 random calendar events for a chat. Each event gets a concrete
 *  day within its template's month/day range. Always picks from the full pool
 *  — calls are idempotent per-chat via the DB, so re-generation for an
 *  existing chat would produce a different set. */
export function generateCalendarEvents(chatId: string, year: number): CalendarEventTemplate[] {
  const shuffled = shuffle(EVENT_TEMPLATES).slice(0, 5);
  return shuffled.map((tpl) => {
    const month = MONTHS_LIST[tpl.monthIndex];
    const day = randInt(tpl.dayRange[0], tpl.dayRange[1]);
    return {
      id: crypto.randomUUID(),
      chatId,
      day: Math.min(30, day), // clamp to 30-day months
      monthName: month,
      year,
      title: tpl.title,
      description: tpl.description,
      icon: tpl.icon,
    };
  });
}

/** Ordered list of month genitive names (index 0 = Měsíce probuzení). */
const MONTHS_LIST: string[] = [
  "Měsíce probuzení",
  "Jarního větru",
  "Měsíce květů",
  "Měsíce slunce",
  "Měsíce žáru",
  "Měsíce bouří",
  "Měsíce sklizně",
  "Měsíce listí",
  "Měsíce mlh",
  "Měsíce mrazu",
  "Měsíce sněhu",
  "Měsíce temnoty",
];

/** Exported for UI display in the calendar panel. */
export const eventTemplates = EVENT_TEMPLATES;

import { execute, newId, nowIso, query } from "../database";

export interface CalendarEvent {
  id: string;
  chatId: string;
  day: number;
  monthName: string;
  year: number;
  title: string;
  description: string;
  icon: string;
  createdAt: string;
}

interface CalendarEventRow {
  id: string;
  chat_id: string;
  day: number;
  month_name: string;
  year: number;
  title: string;
  description: string;
  icon: string;
  created_at: string;
}

function toEvent(row: CalendarEventRow): CalendarEvent {
  return {
    id: row.id,
    chatId: row.chat_id,
    day: row.day,
    monthName: row.month_name,
    year: row.year,
    title: row.title,
    description: row.description,
    icon: row.icon,
    createdAt: row.created_at,
  };
}

export interface CreateCalendarEventInput {
  id: string;
  chatId: string;
  day: number;
  monthName: string;
  year: number;
  title: string;
  description: string;
  icon: string;
}

/** Insert a calendar event. */
export async function createCalendarEvent(input: CreateCalendarEventInput): Promise<void> {
  await execute(
    `INSERT INTO calendar_events (id, chat_id, day, month_name, year, title, description, icon, created_at)
     VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
    [
      input.id,
      input.chatId,
      input.day,
      input.monthName,
      input.year,
      input.title,
      input.description,
      input.icon,
      nowIso(),
    ],
  );
}

/** List all calendar events for a chat, ordered by month and day. */
export async function listCalendarEvents(chatId: string): Promise<CalendarEvent[]> {
  const rows = await query<CalendarEventRow>(
    `SELECT * FROM calendar_events WHERE chat_id = $1
     ORDER BY year ASC, month_name ASC, day ASC`,
    [chatId],
  );
  return rows.map(toEvent);
}

/** Delete a calendar event by id. */
export async function deleteCalendarEvent(id: string): Promise<void> {
  await execute("DELETE FROM calendar_events WHERE id = $1", [id]);
}

